                    /// <returns>An instance of the value returned by the match function.</returns>
                    public TResult Match<TResult>(
                        Func<TResult> matchAnd,
                        Func<TResult> matchOr,
                        Func<TResult> matchNot,
                        Func<TResult> matchEquals,
                        Func<TResult> match,
                        Func<TResult> matchLt,
