                        Func<TResult> matchCasei,
                        Func<TResult> matchAccenti,
                        Func<TResult> matchSContains,
                        Func<TResult> matchSCrosses,
                        Func<TResult> matchSDisjoint,
                        Func<TResult> matchSEquals,
